12	// makeInTreeRoot creates a projectRoot with an in-tree .ddx/ so ddxroot.Path()
13	// returns <projectRoot>/.ddx without attempting git bootstrapping.
14	func makeInTreeRoot(t *testing.T) string {
15		t.Helper()
16		projectRoot := t.TempDir()
17		if err := os.MkdirAll(filepath.Join(projectRoot, ddxroot.DirName), 0o755); err != nil {
18			t.Fatalf("mkdir .ddx: %v", err)
19		}
20		return projectRoot
21	}
