52	func TestPluginLookup_FallsBackToGlobal(t *testing.T) {
53		projectRoot := makeInTreeRoot(t)
54		pluginName := "myplugin"
55	
56		// No project-layer copy.
57		xdg := t.TempDir()
58		t.Setenv("XDG_DATA_HOME", xdg)
59		globalPlugin := filepath.Join(xdg, "ddx", "global", "plugins", pluginName)
60		if err := os.MkdirAll(globalPlugin, 0o755); err != nil {
61			t.Fatalf("mkdir global plugin: %v", err)
62		}
63	
64		gotPath, gotLayer, err := ResolvePlugin(context.Background(), projectRoot, pluginName)
65		if err != nil {
66			t.Fatalf("ResolvePlugin: unexpected error: %v", err)
67		}
68		if gotLayer != "global" {
69			t.Errorf("layer = %q, want %q", gotLayer, "global")
70		}
71		if gotPath != globalPlugin {
72			t.Errorf("path = %q, want %q", gotPath, globalPlugin)
73		}
74	
75		// With neither project nor global copy present, "ddx" falls back to baked-in.
76		projectRoot2 := makeInTreeRoot(t)
77		xdg2 := t.TempDir()
78		t.Setenv("XDG_DATA_HOME", xdg2)
79		gotPath2, gotLayer2, err2 := ResolvePlugin(context.Background(), projectRoot2, "ddx")
80		if err2 != nil {
81			t.Fatalf("ResolvePlugin(ddx baked-in): unexpected error: %v", err2)
82		}
83		if gotLayer2 != "baked-in" {
84			t.Errorf("layer = %q, want %q", gotLayer2, "baked-in")
85		}
86		if gotPath2 != "" {
87			t.Errorf("path = %q, want empty string for baked-in", gotPath2)
88		}
89	}
