91	func TestGlobalPluginDir_HonorsXDGDataHome(t *testing.T) {
92		xdg := t.TempDir()
93		t.Setenv("XDG_DATA_HOME", xdg)
94	
95		pluginName := "testplugin"
96		got := GlobalPluginDir(pluginName)
97		want := filepath.Join(xdg, "ddx", "global", "plugins", pluginName)
98		if got != want {
99			t.Errorf("GlobalPluginDir(%q) = %q, want %q", pluginName, got, want)
100		}
101	
102		// Changing XDG_DATA_HOME changes the result.
103		xdg2 := t.TempDir()
104		t.Setenv("XDG_DATA_HOME", xdg2)
105		got2 := GlobalPluginDir(pluginName)
106		want2 := filepath.Join(xdg2, "ddx", "global", "plugins", pluginName)
107		if got2 != want2 {
108			t.Errorf("GlobalPluginDir(%q) with changed XDG = %q, want %q", pluginName, got2, want2)
109		}
110		if got2 == got {
111			t.Errorf("GlobalPluginDir result did not change when XDG_DATA_HOME changed")
112		}
113	}
