115	func TestPluginLookup_BakedInDefaultOnly(t *testing.T) {
116		projectRoot := makeInTreeRoot(t)
117	
118		// Empty XDG so no global copies exist.
119		t.Setenv("XDG_DATA_HOME", t.TempDir())
120	
121		// "ddx" resolves to baked-in.
122		gotPath, gotLayer, err := ResolvePlugin(context.Background(), projectRoot, "ddx")
123		if err != nil {
124			t.Fatalf("ResolvePlugin(ddx): unexpected error: %v", err)
125		}
126		if gotLayer != "baked-in" {
127			t.Errorf("layer = %q, want %q", gotLayer, "baked-in")
128		}
129		if gotPath != "" {
